// Verify JWT + ownership, same pattern as send-inbox-reply
const authHeader = $('Webhook').item.json.headers?.authorization ?? '';
const token = authHeader.replace(/^Bearer\s+/i, '');
if (!token) throw new Error('Missing authorization token');

const userRes = await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/auth/v1/user`, {
  headers: { Authorization: `Bearer ${token}`, apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY },
});
if (!userRes.ok) throw new Error('Invalid or expired token');
const user = await userRes.json();

const body = $('Webhook').item.json.body;
const { conversationId } = body;

const ownerRes = await fetch(
  `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/agency_owners?user_id=eq.${user.id}&select=id`,
  { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
);
const owners = await ownerRes.json();
if (!owners.length) throw new Error('No agency owner found');
const ownerId = owners[0].id;

const convRes = await fetch(
  `${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/conversations?id=eq.${conversationId}&select=id,lead_phone,client_id,clients(respondfall_number,business_name,review_link,agency_owner_id)`,
  { headers: { apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY, Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}` } }
);
const convs = await convRes.json();
if (!convs.length) throw new Error('Conversation not found');
const conv = convs[0];
if (conv.clients.agency_owner_id !== ownerId) throw new Error('Unauthorized');

return [{ json: { conv } }];

const conv = $('Verify JWT & Ownership').item.json.conv;
const twilioSid = $json.sid;
const now = new Date();
const referralAt = new Date(now.getTime() + 30 * 60 * 1000).toISOString();

// Insert review message
const msgRes = await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/messages`, {
  method: 'POST',
  headers: {
    apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
    Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    conversation_id: conv.id,
    direction: 'outbound',
    body: `Review request sent`,
    message_type: 'review_request',
    twilio_sid: twilioSid,
  }),
});

// Close conversation
await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/conversations?id=eq.${conv.id}`, {
  method: 'PATCH',
  headers: {
    apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
    Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({ status: 'review_sent' }),
});

// Schedule referral message +30 min
await fetch(`${$vars.RESPONDFALL_SUPABASE_URL}/rest/v1/messages`, {
  method: 'POST',
  headers: {
    apikey: $vars.RESPONDFALL_SUPABASE_SERVICE_KEY,
    Authorization: `Bearer ${$vars.RESPONDFALL_SUPABASE_SERVICE_KEY}`,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    conversation_id: conv.id,
    direction: 'outbound',
    body: null,
    message_type: 'referral',
    scheduled_at: referralAt,
  }),
});

return [{ json: { success: true } }];
